import pandas as pd; from collections import Counter
df = pd.read_csv('sample-reviews.csv')
try:
    import jieba
    tok = lambda s: list(jieba.cut(s))
except Exception:
    tok = lambda s: list(s)
words = []
for t in df['text']: words.extend(tok(t))
for w, n in Counter(words).most_common(20):
    print(w, n)
